# 8 — Shemoneh Esrei / Amidah
ENTRIES.append(
    "\u05e7\u05d1\u05e2\u05d5 \u05e4\u05d2\u05d9\u05e9\u05d4 \u05dc\u05e7\u05d4\u05dc \u05e4\u05e8\u05d8\u05d9 \u05e2\u05dd \u05de\u05dc\u05da \u05d4\u05de\u05dc\u05db\u05d9\u05dd! \U0001f451 "
    "\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d9 \u2014 \u05d4\u05de\u05db\u05d5\u05e0\u05d4 \u05d2\u05dd \u05d1\u05e9\u05dd \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u2014 \u05d4\u05d5\u05d0 \u05dc\u05d1 \u05db\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea. "
    "\u05d7\u05db\u05de\u05d9\u05e0\u05d5 \u05d7\u05d9\u05d1\u05e8\u05d5 \u05d0\u05d5\u05ea\u05d4 \u05d1\u05e8\u05d5\u05d7 \u05d4\u05e7\u05d5\u05d3\u05e9, \u05db\u05dc\u05d5\u05de\u05e8 \u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05de\u05e4\u05ea\u05d7 \u05de\u05d3\u05d5\u05d9\u05e7 \u05e9\u05e0\u05d5\u05e2\u05d3 \u05dc\u05e4\u05ea\u05d5\u05d7 \u05e9\u05e2\u05e8\u05d9\u05dd \u05e9\u05de\u05d9\u05d9\u05de\u05d9\u05d9\u05dd \u05d5\u05dc\u05d4\u05d5\u05e8\u05d9\u05d3 \u05d1\u05e8\u05db\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea \u05d5\u05d2\u05e9\u05de\u05d9\u05d5\u05ea! \U0001f513 "
    "\u05de\u05db\u05d9\u05d5\u05d5\u05df \u05e9\u05d6\u05d5 \u05e9\u05d9\u05d7\u05d4 \u05d9\u05e9\u05d9\u05e8\u05d4 \u05e2\u05dd \u05d4\u05f3, \u05dc\u05d4\u05dc\u05db\u05d4 \u05d9\u05e9 \u05db\u05dc\u05dc\u05d9 \"\u05e4\u05e8\u05d5\u05d8\u05d5\u05e7\u05d5\u05dc \u05de\u05dc\u05db\u05d5\u05ea\u05d9\" \u05dc\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05e8\u05d9\u05db\u05d5\u05d6. "
    "\u05e7\u05d5\u05d3\u05dd \u2014 \u05dc\u05e2\u05de\u05d5\u05d3 \u05d1\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e6\u05de\u05d5\u05d3\u05d5\u05ea, \u05d1\u05d7\u05d9\u05db\u05d5\u05d9 \u05d4\u05de\u05dc\u05d0\u05db\u05d9\u05dd \u05e9\u05d9\u05e9 \u05dc\u05d4\u05dd \"\u05e8\u05d2\u05dc \u05d0\u05d7\u05ea\", "
    "\u05dc\u05d4\u05e8\u05d0\u05d5\u05ea \u05de\u05e1\u05d9\u05e8\u05d5\u05ea \u05de\u05d5\u05d7\u05dc\u05d8\u05ea (\u05d5\u05e9\u05d0\u05ea\u05dd \u05dc\u05d0 \u05d4\u05d5\u05dc\u05db\u05d9\u05dd \u05dc\u05e9\u05d5\u05dd \u05de\u05e7\u05d5\u05dd \u05d1\u05d6\u05de\u05df \u05e9\u05de\u05d3\u05d1\u05e8\u05d9\u05dd \u05e2\u05dd \u05d4\u05de\u05dc\u05da!). \U0001f607 "
    "\u05d2\u05dd \u05e4\u05d5\u05e0\u05d9\u05dd \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u2014 \u05d0\u05d9\u05e4\u05d4 \u05e9\u05d0\u05ea\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd \u2014 \u05db\u05d3\u05d9 \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05dc\u05d1 \u05dc\u05e2\u05d1\u05e8 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9! \U0001f3db\ufe0f "
    "\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05d7\u05d5\u05dc\u05e7\u05ea \u05dc\u05e9\u05dc\u05d5\u05e9\u05d4 \u05d7\u05dc\u05e7\u05d9\u05dd: \u05e9\u05dc\u05d5\u05e9 \u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05d1\u05d7, \u05e9\u05dc\u05d5\u05e9 \u05e2\u05e9\u05e8\u05d4 \u05d1\u05e7\u05e9\u05d5\u05ea \u05dc\u05d3\u05d1\u05e8\u05d9\u05dd \u05db\u05de\u05d5 \u05d7\u05db\u05de\u05d4, \u05d1\u05e8\u05d9\u05d0\u05d5\u05ea \u05d5\u05e9\u05d2\u05e9\u05d5\u05d2, "
    "\u05d5\u05e9\u05dc\u05d5\u05e9 \u05d1\u05e8\u05db\u05d5\u05ea \u05e1\u05d9\u05d5\u05dd \u05e9\u05dc \u05d4\u05d5\u05d3\u05d9\u05d4. \u05d1\u05e9\u05d1\u05ea \u05d5\u05d1\u05d7\u05d2\u05d9\u05dd, \u05e6\u05d5\u05e8\u05ea \u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05d0\u05de\u05e6\u05e2\u05d9\u05d5\u05ea \u05de\u05e9\u05ea\u05e0\u05d4 \u2014 \u05d5\u05d3\u05d0\u05d5 \u05e9\u05d0\u05ea\u05dd \u05e7\u05d5\u05e8\u05d0\u05d9\u05dd \u05d0\u05ea \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05d4\u05e0\u05db\u05d5\u05e0\u05d4 \u05de\u05df \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8! \U0001f4dc "
    "\u05d1\u05e2\u05d5\u05d3 \u05e9\u05db\u05d5\u05d5\u05e0\u05d4 \u05d8\u05d5\u05d1\u05d4 \u05dc\u05d0\u05d5\u05e8\u05da \u05db\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d4\u05d7\u05db\u05de\u05d9\u05dd \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05e9\u05d4\u05d9\u05d0 \u05e7\u05e8\u05d9\u05d8\u05d9\u05ea \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05d1\u05e8\u05db\u05d4 \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4 \"\u05d0\u05d1\u05d5\u05ea\" \u2014 "
    "\u05d0\u05dd \u05d0\u05d9\u05d1\u05d3\u05ea\u05dd \u05e9\u05dd \u05d0\u05ea \u05d4\u05e8\u05d9\u05db\u05d5\u05d6, \u05e4\u05e1\u05e4\u05e1\u05ea\u05dd \u05d0\u05ea \u05dc\u05d1 \u05d4\u05de\u05e4\u05d2\u05e9 (\u05d0\u05e9\u05db\u05e0\u05d6\u05d9\u05dd \u05dc\u05d0 \u05d7\u05d5\u05d6\u05e8\u05d9\u05dd \u05dc\u05d7\u05d6\u05d5\u05e8, \u05e1\u05e4\u05e8\u05d3\u05d9\u05dd \u05db\u05df)! \U0001f54a\ufe0f "
    "\u05d4\u05d9\u05db\u05e0\u05e1\u05d5 \u05dc\u05de\u05de\u05d3 \u05d0\u05d7\u05e8 \u05d5\u05d4\u05d5\u05e8\u05d9\u05d3\u05d5 \u05d0\u05ea \u05db\u05dc \u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05d4\u05f3 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05ea\u05ea \u05dc\u05db\u05dd! \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3! \U0001f38a\U0001f64f "
    "\u05de\u05e7\u05d5\u05e8: \u05ea\u05dc\u05de\u05d5\u05d3, \u05d1\u05e8\u05db\u05d5\u05ea \u05dc\u05d3 \u05e2\u05b2\u05d1; \u05e9\u05d5\u05dc\u05d7\u05df \u05e2\u05e8\u05d5\u05da, \u05d0\u05d5\u05e8\u05d7 \u05d7\u05d9\u05d9\u05dd \u05e6\u05d4-\u05e6\u05d7."
)

if __name__ == "__main__":
    print(len(ENTRIES), CORRUPTION_RE.findall(ENTRIES[-1]))
